fixes.code:
struct MyVec(Vec<i32>);

impl std::fmt::Display for MyVec {
    fn fmt(&self, f: &mut std::fmt::Formatter) -> std::fmt::Result {
        write!(f, "{:?}", self.0)
    }
}

trait PrettyPrint {
    fn pretty_print(&self) -> String;
}

impl PrettyPrint for Vec<i32> {
    fn pretty_print(&self) -> String {
        format!("{:?}", self)
    }
}
